+    // tokenFill calculates how many tokens should be added for elapsed d.
+    tokenFill := func(d time.Duration) int {
+        // Multiply rate by fraction of window elapsed.
+        // Use integer arithmetic to avoid floating point.
+        // tokens = floor(Rate * d / Window)
+        return int((int64(cfg.Rate) * d.Nanoseconds()) / cfg.Window.Nanoseconds())
+    }
