+    return &bucketLimiter{
+        cfg:       cfg,
+        burst:     burst,
+        fillFn:    tokenFill,
+        clock:     clockOrDefault(clock),
+        state:     make(map[string]*bucketState),
+        stateLock: sync.Mutex{},
+    }
