 // clockOrDefault returns the provided Clock or a real‑time implementation.
 func clockOrDefault(c Clock) Clock {
     if c != nil {
         return c
     }
     return realClock{}
 }

 // realClock implements Clock using time.Now().
 type realClock struct{}

 func (realClock) Now() time.Time { return time.Now() }

 // noopLimiter denies all requests (used for invalid config).
 type noopLimiter struct{}

 func (noopLimiter) Allow(string) bool { return false }
 func (noopLimiter) Reset(string)      {}

 // bucketLimiter implements Limiter using a token bucket per key.
 type bucketLimiter struct {
     cfg   Config
     burst int
     // fillFn computes token addition based on elapsed duration.
     fillFn func(time.Duration) int
     clock Clock
     // state maps keys to their bucket state.
     state     map[string]*bucketState
     stateLock sync.Mutex
 }

 // bucketState holds the mutable state for a single key.
 type bucketState struct {
     // last time tokens were refilled.
     last time.Time
     // current token count.
     tokens int
 }

 // Allow checks and consumes a token for the given key.
 func (b *bucketLimiter) Allow(key string) bool {
     now := b.clock.Now()

     // Retrieve or create bucket state for the key.
     b.stateLock.Lock()
     s, ok := b.state[key]
     if !ok {
         // New key starts with a full bucket.
         s = &bucketState{
             last:   now,
             tokens: b.burst,
         }
         b.state[key] = s
         b.stateLock.Unlock()
         // Consume one token.
         s.tokens--
         return true
     }
     // Hold the state while we compute.
     b.stateLock.Unlock()

     // Refill tokens based on elapsed time.
     elapsed := now.Sub(s.last)
     if elapsed > 0 {
         add := b.fillFn(elapsed)
         if add > 0 {
             s.tokens += add
             if s.tokens > b.burst {
                 s.tokens = b.burst
             }
             s.last = now
         }
     }

     if s.tokens <= 0 {
         return false
     }
     s.tokens--
     return true
 }

 // Reset clears the bucket for a key, restoring a full burst.
 func (b *bucketLimiter) Reset(key string) {
     now := b.clock.Now()
     b.stateLock.Lock()
     defer b.stateLock.Unlock()
     delete(b.state, key)
     // Recreate with full burst so next Allow starts fresh.
     b.state[key] = &bucketState{
         last:   now,
         tokens: b.burst,
     }
 }
